#!/usr/bin/env node
// Compiles the FSH IG with Sushi, then copies the generated resource JSON
// into web/src/data/fhir/ so the React app can import FHIR resources directly.
//
// FSH is the single source of truth for SPiER's FHIR shapes. Anything under
// web/src/data/fhir/ is a build artifact — gitignored, regenerated by this
// script via `npm run copy-fhir` (also invoked by `predev` / `prebuild`).
//
// The SUSHI compile is slow (~30s), so this script is incremental: it skips the
// compile when the generated artifacts are already newer than every FSH input
// (see the "Staleness check" section below). `--force` always recompiles.

import { spawnSync } from 'node:child_process'
import { mkdirSync, readdirSync, copyFileSync, readFileSync, writeFileSync, rmSync, statSync } from 'node:fs'
import { dirname, resolve, join } from 'node:path'
import { fileURLToPath } from 'node:url'

const scriptPath = fileURLToPath(import.meta.url)
const __dirname = dirname(scriptPath)
const repoRoot = resolve(__dirname, '..', '..')
const igDir = join(repoRoot, 'ig')
const generatedDir = join(igDir, 'fsh-generated', 'resources')
const destDir = join(repoRoot, 'web', 'src', 'data', 'fhir')
const catalogDir = join(repoRoot, 'web', 'src', 'data', 'catalog')

// Inputs that determine the SUSHI output. If none of these change, recompiling
// produces byte-identical artifacts (see the staleness check below).
const fshInputDir = join(igDir, 'input', 'fsh')
const sushiConfig = join(igDir, 'sushi-config.yaml')
// The single TypeScript artifact this script emits (writeCarePlanProfileTypes).
const generatedTsPath = join(catalogDir, 'care-plan-profiles.generated.ts')

// ImplementationGuide is IG manifest metadata, not a domain resource consumed by the app.
const EXCLUDE_PREFIXES = ['ImplementationGuide-']

function log(msg) {
  console.log(`[copy-fhir] ${msg}`)
}

// ---------------------------------------------------------------------------
// Staleness check
// ---------------------------------------------------------------------------
// Why this exists:
//   `predev` runs this script on EVERY `npm run dev`, and the SUSHI FSH compile
//   takes ~30s. But the FSH sources rarely change between dev starts, and SUSHI
//   is deterministic — if no input changed, recompiling produces identical
//   output. So we skip the compile (and the copy) whenever the artifacts the app
//   consumes are already newer than every input that feeds them. This turns the
//   common case (no FSH edits) from a ~30s wait into an instant no-op, while
//   still regenerating automatically the first time after any FSH change.
//
// What counts as an input:
//   - everything under ig/input/fsh/ (the FSH source of truth)
//   - ig/sushi-config.yaml (canonical, version, dependencies — all shape output)
//   - this script itself (its copy/exclude/codegen logic shapes the output too)
//
// What counts as output:
//   - the resource JSON the app imports (web/src/data/fhir/)
//   - the generated TypeScript (care-plan-profiles.generated.ts)
//   We deliberately key off these CONSUMED artifacts, not ig/fsh-generated/, so
//   that a cleaned/stale intermediate dir doesn't matter — if the app's inputs
//   are current, there is nothing to do.
//
// Correctness:
//   We skip only when the OLDEST output postdates the NEWEST input, so a single
//   stale output forces a full rebuild. mtime ties (rare, coarse filesystems)
//   resolve toward rebuilding — conservative by design. A fresh clone has no
//   outputs, so the check fails and we build. `--force` bypasses the check
//   entirely; `prebuild` passes it so release builds never trust mtimes.

function walkFiles(dir) {
  const out = []
  let entries
  try {
    entries = readdirSync(dir, { withFileTypes: true })
  } catch {
    return out // missing dir contributes no files
  }
  for (const entry of entries) {
    const full = join(dir, entry.name)
    if (entry.isDirectory()) out.push(...walkFiles(full))
    else out.push(full)
  }
  return out
}

function mtimeMs(path) {
  try {
    return statSync(path).mtimeMs
  } catch {
    return null // missing files are ignored by callers
  }
}

function isUpToDate() {
  // Both consumed artifacts must be present, or there is nothing to trust:
  //   - the copied resource dir (must contain files), and
  //   - the generated TS bundle (a single file).
  // Filtering missing paths out of the comparison would let a deleted output
  // (empty destDir, removed generated TS) pass as "up to date" and skip a
  // rebuild the app actually needs — so check existence explicitly first.
  const destFiles = walkFiles(destDir)
  if (destFiles.length === 0) return false // fresh clone / cleaned tree → build

  const tsMtime = mtimeMs(generatedTsPath)
  if (tsMtime === null) return false // generated TS deleted → build

  const inputFiles = [sushiConfig, scriptPath, ...walkFiles(fshInputDir)]
  const inputTimes = inputFiles.map(mtimeMs).filter((t) => t !== null)
  // No inputs found is unexpected; rebuild rather than silently skip.
  if (inputTimes.length === 0) return false

  const newestInput = Math.max(...inputTimes)
  const oldestOutput = Math.min(...destFiles.map(mtimeMs), tsMtime)
  return oldestOutput > newestInput
}

function runSushi() {
  log('compiling FSH with sushi...')
  // Run from the script's cwd (web/ when invoked via `npm run`) so npx finds
  // the local fsh-sushi in web/node_modules/.bin. Pass igDir as an argument
  // — sushi treats it as the project folder and writes to ig/fsh-generated/.
  const result = spawnSync('npx', ['--no-install', 'fsh-sushi', igDir], {
    stdio: 'inherit',
    shell: process.platform === 'win32',
  })
  if (result.status !== 0) {
    console.error('[copy-fhir] sushi failed — aborting copy')
    process.exit(result.status ?? 1)
  }
}

function clearDest() {
  try {
    rmSync(destDir, { recursive: true, force: true })
  } catch {
    // ignore
  }
  mkdirSync(destDir, { recursive: true })
}

function copyResources() {
  let entries
  try {
    entries = readdirSync(generatedDir)
  } catch (err) {
    console.error(`[copy-fhir] expected ${generatedDir} to exist after sushi; got ${err.message}`)
    process.exit(1)
  }

  let copied = 0
  let skipped = 0
  for (const name of entries) {
    if (!name.endsWith('.json')) continue
    if (EXCLUDE_PREFIXES.some((p) => name.startsWith(p))) {
      skipped += 1
      continue
    }
    const src = join(generatedDir, name)
    if (!statSync(src).isFile()) continue
    copyFileSync(src, join(destDir, name))
    copied += 1
  }
  log(`copied ${copied} resource(s) to web/src/data/fhir/ (skipped ${skipped})`)
}

/**
 * Emit a TypeScript file declaring the union of canonical URLs for every
 * SPiER StructureDefinition that constrains CarePlan. The CarePlan mappers
 * use this union to type their `meta.profile` claim — FSH stays the single
 * source of truth.
 */
function writeCarePlanProfileTypes() {
  const sdFiles = readdirSync(destDir).filter(
    (n) => n.startsWith('StructureDefinition-') && n.endsWith('.json'),
  )
  const urls = []
  for (const name of sdFiles) {
    const doc = JSON.parse(readFileSync(join(destDir, name), 'utf8'))
    if (doc.kind === 'resource' && doc.type === 'CarePlan' && typeof doc.url === 'string') {
      urls.push(doc.url)
    }
  }
  urls.sort()

  const outPath = join(catalogDir, 'care-plan-profiles.generated.ts')
  const lines = [
    '// Auto-generated by web/scripts/copy-fhir.mjs — do not edit by hand.',
    '// Source: ig/input/fsh/<tool>.fsh (Profile: ... Parent: CarePlan).',
    '// Regenerated on every `npm run copy-fhir` (also runs as predev / prebuild).',
    '',
    'export const CAREPLAN_PROFILE_URLS = [',
    ...urls.map((u) => `  ${JSON.stringify(u)},`),
    '] as const',
    '',
    'export type CarePlanProfileUrl = (typeof CAREPLAN_PROFILE_URLS)[number]',
    '',
  ]
  // `recursive: true` is idempotent — guards against the rare case where
  // the catalog directory has been deleted (e.g., partial clone, manual rm).
  mkdirSync(catalogDir, { recursive: true })
  writeFileSync(outPath, lines.join('\n'), 'utf8')
  log(`emitted ${outPath.replace(repoRoot + '/', '')} with ${urls.length} CarePlan profile URL(s)`)
}

const force = process.argv.includes('--force')
if (!force && isUpToDate()) {
  log('FHIR artifacts are up to date with FSH sources — skipping SUSHI compile.')
  log('(Edit any .fsh or sushi-config.yaml to trigger a rebuild, or run with --force.)')
  process.exit(0)
}

runSushi()
clearDest()
copyResources()
writeCarePlanProfileTypes()
